import type { PrismaClient } from "@prisma/client";
import { prisma as defaultPrisma } from "./client.js";

/**
 * Shared "submit an entry, then vote" storage for the two structurally
 * identical community battle games: playlist-battle (song submissions) and
 * creativity-challenge (meme/idea submissions). Both are votes-desc/id-asc
 * rankers over submitted entries (see `resolvePlaylistBattle` /
 * `resolveCreativityChallenge` in `@superbot/module-games`), so they share
 * one table (discriminated by `kind`) instead of two near-duplicate ones.
 *
 * The generic Poll/PollVote models were considered first but don't fit:
 * Poll.options is a fixed JSON array chosen once at creation time, with no
 * room for a submitter, arbitrary per-entry content, or entries added after
 * the poll opens — exactly what these two games need. PollVote.optionIndex
 * also only makes sense as an index into that fixed array, not a stable id
 * for a dynamically-submitted entry.
 *
 * A round (one open battle/challenge instance in a chat) has no header row
 * of its own here — the "is a round currently open, and what's its id"
 * pointer is tracked by the caller via the existing generic
 * `ChatSettingRepository` (key e.g. `battle:playlist`), the same pattern
 * already used for other one-small-value-per-chat needs. This repository
 * only persists entries and votes for whatever roundId it's given.
 */
export type BattleKind = "playlist" | "creativity";

/** One submitted entry plus its current vote count. */
export interface BattleEntryRecord {
  readonly id: string;
  readonly kind: BattleKind;
  readonly roundId: string;
  readonly submittedBy: bigint;
  readonly content: string;
  readonly votes: number;
  readonly createdAt: Date;
}

export type SubmitBattleEntryResult =
  | { readonly outcome: "submitted"; readonly entry: BattleEntryRecord }
  | { readonly outcome: "duplicate" };

export type VoteBattleEntryResult =
  | { readonly outcome: "voted" }
  | { readonly outcome: "not-found" }
  | { readonly outcome: "self-vote" }
  | { readonly outcome: "duplicate" };

export interface BattleEntriesRepository {
  /**
   * Records a new submission for the given (already-open) round. Returns
   * "duplicate" — no row written — when this user already submitted an
   * entry in this round: one submission per user per round.
   */
  submitEntry(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
    submittedBy: bigint,
    content: string,
  ): Promise<SubmitBattleEntryResult>;

  /**
   * Casts one vote for `entryId`, scoped to `roundId`. Validates the entry
   * actually belongs to (tenantId, chatId, kind, roundId) so a stale entryId
   * from a round that already closed is rejected as "not-found" instead of
   * silently voting into a dead round. "self-vote" blocks voting for one's
   * own submission. "duplicate" means this voter already used their one vote
   * for this round (on any entry) — mirrors PollVote's one-vote-per-poll rule.
   */
  voteEntry(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
    entryId: string,
    voterId: bigint,
  ): Promise<VoteBattleEntryResult>;

  /** Every entry submitted in this round, each with its current vote count. */
  listRoundEntries(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
  ): Promise<BattleEntryRecord[]>;
}

const isUniqueViolation = (error: unknown): boolean =>
  typeof error === "object" &&
  error !== null &&
  "code" in error &&
  (error as { code?: string }).code === "P2002";

export class PrismaBattleEntriesRepository implements BattleEntriesRepository {
  constructor(private readonly client: PrismaClient = defaultPrisma) {}

  async submitEntry(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
    submittedBy: bigint,
    content: string,
  ): Promise<SubmitBattleEntryResult> {
    try {
      const row = await this.client.battleEntry.create({
        data: { tenantId, chatId, kind, roundId, submittedBy, content },
      });
      return {
        outcome: "submitted",
        entry: {
          id: row.id,
          kind: row.kind as BattleKind,
          roundId: row.roundId,
          submittedBy: row.submittedBy,
          content: row.content,
          votes: 0,
          createdAt: row.createdAt,
        },
      };
    } catch (error) {
      if (isUniqueViolation(error)) {
        return { outcome: "duplicate" };
      }
      throw error;
    }
  }

  async voteEntry(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
    entryId: string,
    voterId: bigint,
  ): Promise<VoteBattleEntryResult> {
    const entry = await this.client.battleEntry.findUnique({
      where: { id: entryId },
    });

    if (
      !entry ||
      entry.tenantId !== tenantId ||
      entry.chatId !== chatId ||
      entry.kind !== kind ||
      entry.roundId !== roundId
    ) {
      return { outcome: "not-found" };
    }

    if (entry.submittedBy === voterId) {
      return { outcome: "self-vote" };
    }

    try {
      await this.client.battleEntryVote.create({
        data: { entryId, roundId, voterId },
      });
      return { outcome: "voted" };
    } catch (error) {
      if (isUniqueViolation(error)) {
        return { outcome: "duplicate" };
      }
      throw error;
    }
  }

  async listRoundEntries(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
  ): Promise<BattleEntryRecord[]> {
    const rows = await this.client.battleEntry.findMany({
      where: { tenantId, chatId, kind, roundId },
      include: { _count: { select: { votes: true } } },
      orderBy: { createdAt: "asc" },
    });

    return rows.map(
      (row: {
        id: string;
        kind: string;
        roundId: string;
        submittedBy: bigint;
        content: string;
        createdAt: Date;
        _count: { votes: number };
      }) => ({
        id: row.id,
        kind: row.kind as BattleKind,
        roundId: row.roundId,
        submittedBy: row.submittedBy,
        content: row.content,
        votes: row._count.votes,
        createdAt: row.createdAt,
      }),
    );
  }
}

/** Store en memoria usado como default del constructor (tests). */
export class InMemoryBattleEntriesRepository implements BattleEntriesRepository {
  private readonly entries = new Map<
    string,
    {
      id: string;
      tenantId: string;
      chatId: string;
      kind: BattleKind;
      roundId: string;
      submittedBy: bigint;
      content: string;
      createdAt: Date;
    }
  >();
  private readonly votes = new Map<
    string,
    { entryId: string; roundId: string; voterId: bigint }
  >();
  private sequence = 0;

  private nextId(prefix: string): string {
    this.sequence += 1;
    return `${prefix}_${this.sequence}`;
  }

  private toRecord(entry: {
    id: string;
    kind: BattleKind;
    roundId: string;
    submittedBy: bigint;
    content: string;
    createdAt: Date;
  }): BattleEntryRecord {
    const votes = [...this.votes.values()].filter(
      (vote) => vote.entryId === entry.id,
    ).length;
    return {
      id: entry.id,
      kind: entry.kind,
      roundId: entry.roundId,
      submittedBy: entry.submittedBy,
      content: entry.content,
      votes,
      createdAt: entry.createdAt,
    };
  }

  async submitEntry(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
    submittedBy: bigint,
    content: string,
  ): Promise<SubmitBattleEntryResult> {
    const alreadySubmitted = [...this.entries.values()].some(
      (entry) =>
        entry.roundId === roundId &&
        entry.kind === kind &&
        entry.submittedBy === submittedBy,
    );
    if (alreadySubmitted) {
      return { outcome: "duplicate" };
    }

    const entry = {
      id: this.nextId("entry"),
      tenantId,
      chatId,
      kind,
      roundId,
      submittedBy,
      content,
      createdAt: new Date(),
    };
    this.entries.set(entry.id, entry);
    return { outcome: "submitted", entry: this.toRecord(entry) };
  }

  async voteEntry(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
    entryId: string,
    voterId: bigint,
  ): Promise<VoteBattleEntryResult> {
    const entry = this.entries.get(entryId);
    if (
      !entry ||
      entry.tenantId !== tenantId ||
      entry.chatId !== chatId ||
      entry.kind !== kind ||
      entry.roundId !== roundId
    ) {
      return { outcome: "not-found" };
    }

    if (entry.submittedBy === voterId) {
      return { outcome: "self-vote" };
    }

    const alreadyVoted = [...this.votes.values()].some(
      (vote) => vote.roundId === roundId && vote.voterId === voterId,
    );
    if (alreadyVoted) {
      return { outcome: "duplicate" };
    }

    const voteId = this.nextId("vote");
    this.votes.set(voteId, { entryId, roundId, voterId });
    return { outcome: "voted" };
  }

  async listRoundEntries(
    tenantId: string,
    chatId: string,
    kind: BattleKind,
    roundId: string,
  ): Promise<BattleEntryRecord[]> {
    return [...this.entries.values()]
      .filter(
        (entry) =>
          entry.tenantId === tenantId &&
          entry.chatId === chatId &&
          entry.kind === kind &&
          entry.roundId === roundId,
      )
      .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime())
      .map((entry) => this.toRecord(entry));
  }
}

repositoryTestFileContent:
import { describe, expect, it } from "vitest";
import { InMemoryBattleEntriesRepository } from "./battle-entries-repository.js";

describe("InMemoryBattleEntriesRepository", () => {
  it("submits an entry and lists it with zero votes", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    const result = await repo.submitEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      111n,
      "Bohemian Rhapsody",
    );
    expect(result.outcome).toBe("submitted");

    const entries = await repo.listRoundEntries("t1", "c1", "playlist", "round-1");
    expect(entries).toHaveLength(1);
    expect(entries[0]?.content).toBe("Bohemian Rhapsody");
    expect(entries[0]?.votes).toBe(0);
    expect(entries[0]?.submittedBy).toBe(111n);
  });

  it("rejects a second submission from the same user in the same round", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    await repo.submitEntry("t1", "c1", "playlist", "round-1", 111n, "Song A");
    const second = await repo.submitEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      111n,
      "Song B",
    );
    expect(second.outcome).toBe("duplicate");
    expect(
      await repo.listRoundEntries("t1", "c1", "playlist", "round-1"),
    ).toHaveLength(1);
  });

  it("allows the same user to submit again in a different round", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    await repo.submitEntry("t1", "c1", "playlist", "round-1", 111n, "Song A");
    const second = await repo.submitEntry(
      "t1",
      "c1",
      "playlist",
      "round-2",
      111n,
      "Song B",
    );
    expect(second.outcome).toBe("submitted");
  });

  it("keeps playlist and creativity entries of the same round id separate", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    await repo.submitEntry("t1", "c1", "playlist", "round-1", 111n, "Song A");
    await repo.submitEntry("t1", "c1", "creativity", "round-1", 111n, "Meme A");
    expect(
      await repo.listRoundEntries("t1", "c1", "playlist", "round-1"),
    ).toHaveLength(1);
    expect(
      await repo.listRoundEntries("t1", "c1", "creativity", "round-1"),
    ).toHaveLength(1);
  });

  it("records a vote and reflects it in the vote count", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    const submitted = await repo.submitEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      111n,
      "Song A",
    );
    if (submitted.outcome !== "submitted") {
      throw new Error("expected submission to succeed");
    }

    const vote = await repo.voteEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      submitted.entry.id,
      222n,
    );
    expect(vote.outcome).toBe("voted");

    const entries = await repo.listRoundEntries("t1", "c1", "playlist", "round-1");
    expect(entries[0]?.votes).toBe(1);
  });

  it("rejects voting for one's own entry", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    const submitted = await repo.submitEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      111n,
      "Song A",
    );
    if (submitted.outcome !== "submitted") {
      throw new Error("expected submission to succeed");
    }

    const vote = await repo.voteEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      submitted.entry.id,
      111n,
    );
    expect(vote.outcome).toBe("self-vote");
  });

  it("rejects a second vote from the same user in the same round", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    const a = await repo.submitEntry("t1", "c1", "playlist", "round-1", 111n, "A");
    const b = await repo.submitEntry("t1", "c1", "playlist", "round-1", 222n, "B");
    if (a.outcome !== "submitted" || b.outcome !== "submitted") {
      throw new Error("expected submissions to succeed");
    }

    const firstVote = await repo.voteEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      a.entry.id,
      333n,
    );
    expect(firstVote.outcome).toBe("voted");

    // Same voter, different entry, same round -> still only one vote allowed.
    const secondVote = await repo.voteEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      b.entry.id,
      333n,
    );
    expect(secondVote.outcome).toBe("duplicate");
  });

  it("rejects voting for an entry that belongs to a different (e.g. closed) round", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    const a = await repo.submitEntry("t1", "c1", "playlist", "round-1", 111n, "A");
    if (a.outcome !== "submitted") {
      throw new Error("expected submission to succeed");
    }

    const vote = await repo.voteEntry(
      "t1",
      "c1",
      "playlist",
      "round-2",
      a.entry.id,
      222n,
    );
    expect(vote.outcome).toBe("not-found");
  });

  it("rejects voting for an unknown entry id", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    const vote = await repo.voteEntry(
      "t1",
      "c1",
      "playlist",
      "round-1",
      "nonexistent",
      222n,
    );
    expect(vote.outcome).toBe("not-found");
  });

  it("produces a votes-desc ranking input consistent with resolvePlaylistBattle", async () => {
    const repo = new InMemoryBattleEntriesRepository();
    const a = await repo.submitEntry("t1", "c1", "playlist", "r1", 1n, "Song A");
    const b = await repo.submitEntry("t1", "c1", "playlist", "r1", 2n, "Song B");
    if (a.outcome !== "submitted" || b.outcome !== "submitted") {
      throw new Error("expected submissions to succeed");
    }
    await repo.voteEntry("t1", "c1", "playlist", "r1", b.entry.id, 3n);
    await repo.voteEntry("t1", "c1", "playlist", "r1", b.entry.id, 4n);
    await repo.voteEntry("t1", "c1", "playlist", "r1", a.entry.id, 5n);

    const entries = await repo.listRoundEntries("t1", "c1", "playlist", "r1");
    const bEntry = entries.find((entry) => entry.id === b.entry.id);
    const aEntry = entries.find((entry) => entry.id === a.entry.id);
    expect(bEntry?.votes).toBe(2);
    expect(aEntry?.votes).toBe(1);
  });
});

